import React, { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import { adminApi } from '../api/authApi';
import { useAuth } from '../context/AuthContext';
import Card from '../components/Card';
import { Shield, Users, Trash2 } from 'lucide-react';

const AdminDashboard = () => {
  const { user } = useAuth();
  const [users, setUsers] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedRole, setSelectedRole] = useState('all'); // all|admin|alumni|student
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const roleToLabel = (role) => {
    if (role === 'admin') return 'Admin';
    if (role === 'alumni') return 'Alumni';
    if (role === 'student') return 'Student';
    return role || '-';
  };

  const fetchUsers = async () => {
    setError(null);
    try {
      setLoading(true);
      const params = {};
      const trimmedSearch = searchTerm.trim();
      if (trimmedSearch) params.search = trimmedSearch;
      if (selectedRole !== 'all') params.role = selectedRole;

      const response = await adminApi.getUsers(params);
      setUsers(response.data?.data || []);
    } catch (err) {
      setUsers([]);
      setError(err?.response?.data?.message || 'Failed to fetch users');
    } finally {
      setLoading(false);
    }
  };

  // Debounced search + refetch on role changes.
  useEffect(() => {
    const handle = setTimeout(() => {
      fetchUsers();
    }, 400);

    return () => clearTimeout(handle);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [searchTerm, selectedRole]);

  const handleDeleteUser = async (userId) => {
    const confirmed = window.confirm('Are you sure you want to delete this user? This action cannot be undone.');
    if (!confirmed) return;

    try {
      setLoading(true);
      await adminApi.deleteUser(userId);
      toast.success('User deleted successfully');
      await fetchUsers();
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to delete user');
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2 flex items-center gap-3">
            <Shield className="h-8 w-8 text-blue-700" /> Admin Dashboard
          </h1>
          <p className="text-gray-600">
            Welcome{user?.name ? `, ${user.name}` : ''}. Manage and verify accounts.
          </p>
        </div>

        <Card className="mb-6 p-4">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
              <label className="text-sm font-medium text-gray-700">Search users</label>
              <input
                className="form-input mt-2"
                type="text"
                placeholder="Search by name or email..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            <div>
              <label className="text-sm font-medium text-gray-700">Role filter</label>
              <select
                className="form-select mt-2"
                value={selectedRole}
                onChange={(e) => setSelectedRole(e.target.value)}
              >
                <option value="all">All</option>
                <option value="admin">Admin</option>
                <option value="alumni">Alumni</option>
                <option value="student">Student</option>
              </select>
            </div>

            <div className="text-sm text-gray-600 flex items-center gap-2">
              <Users className="h-4 w-4" />
              Showing {users.length} user(s)
            </div>
          </div>
        </Card>

        {error && (
          <div className="mb-4">
            <div className="text-sm text-red-700 bg-red-50 border border-red-200 rounded-md px-4 py-3">
              {error}
            </div>
          </div>
        )}

        {loading ? (
          <div className="min-h-[240px] flex items-center justify-center">
            <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-blue-600" />
          </div>
        ) : (
          <Card>
            <div className="overflow-x-auto">
              <table className="min-w-full text-left">
                <thead>
                  <tr className="border-b">
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Name</th>
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Email</th>
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Role</th>
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Created At</th>
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {users.map((u) => {
                    const created = u.createdAt ? new Date(u.createdAt) : null;
                    return (
                      <tr key={u._id} className="border-b">
                        <td className="py-3 px-4 text-sm text-gray-900 font-medium">{u.name}</td>
                        <td className="py-3 px-4 text-sm text-gray-600">{u.email}</td>
                        <td className="py-3 px-4 text-sm text-gray-600">{roleToLabel(u.role)}</td>
                        <td className="py-3 px-4 text-sm text-gray-600">
                          {created ? created.toLocaleDateString() : '-'}
                        </td>
                        <td className="py-3 px-4 text-sm">
                          <button
                            className="btn btn-outline text-red-600 hover:text-red-800"
                            onClick={() => handleDeleteUser(u._id)}
                          >
                            <Trash2 className="h-4 w-4 mr-2" />
                            Delete
                          </button>
                        </td>
                      </tr>
                    );
                  })}
                  {users.length === 0 && (
                    <tr>
                      <td colSpan={5} className="py-10 text-center text-gray-500">
                        No users found.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </Card>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
